"""Sub-renderers for the system-picture proof-ledger projection.

Each function returns a list of markdown lines for one ledger section.
"""

from __future__ import annotations

from .system_picture_models import SystemPictureSection, SystemPictureSnapshot


def render_ledger_header(date: str) -> list[str]:
    """Render the ledger preamble: title, status line, upkeep contract."""
    return [
        "<!-- Generated by `python3 dev/scripts/devctl.py system-picture --write-ledger --format md`; edit `dev/scripts/devctl/platform/system_picture_render.py` instead of hand-editing this file. -->",
        "",
        "# AI Governance Platform Proof Ledger",
        "",
        f"**Status**: active reference  |  **Last updated**: {date} | **Owner:** Tooling/control plane/product architecture",
        "",
        "Reference-only proof and differentiation ledger for the `MP-377` AI governance",
        "platform work.",
        "",
        "This file is generated from the repo-owned `devctl system-picture` reducer.",
        "It is not execution authority. Canonical execution state remains in:",
        "",
        "- `dev/active/MASTER_PLAN.md`",
        "- `dev/active/ai_governance_platform.md`",
        "- `dev/active/platform_authority_loop.md`",
        "- `dev/active/portable_code_governance.md`",
        "",
        "## Upkeep Contract",
        "",
        "Refresh this ledger through the repo-owned command whenever proof claims,",
        "artifact owners, or cross-repo evidence materially change:",
        "",
        "```bash",
        "python3 dev/scripts/devctl.py system-picture --format md",
        "python3 dev/scripts/devctl.py system-picture --write-ledger --format md",
        "```",
        "",
        "Keep the underlying machine truth in the typed/runtime artifacts and managed",
        "reports. Keep accepted execution decisions in the owner plans, not here.",
        "",
    ]


