def render_proof_snapshot(
    *,
    snapshot: SystemPictureSnapshot,
    date: str,
    startup_summary: dict[str, object],
    graph_summary: dict[str, object],
    review_summary: dict[str, object],
    governance_summary: dict[str, object],
    external_summary: dict[str, object],
    data_science_summary: dict[str, object],
) -> list[str]:
    """Render the proof-snapshot signal table from section summaries."""
    return [
        "## Current Proof Snapshot",
        "",
        f"Baseline observed from the generated `system-picture` snapshot `{snapshot.snapshot_id}` on {date}:",
        "",
        "| Signal | Current evidence |",
        "|---|---|",
        f"| Branch | `{snapshot.current_branch or '(unknown)'}` |",
        "| Bootstrap graph | "
        f"`{graph_summary.get('node_count', 'n/a')}` source files, "
        f"`{graph_summary.get('guard_count', 'n/a')}` guards, "
        f"`{graph_summary.get('probe_count', 'n/a')}` probes, "
        f"`{graph_summary.get('plan_count', 'n/a')}` active plans, "
        f"`{graph_summary.get('edge_count', 'n/a')}` edges |",
        "| Startup authority | "
        f"`action={startup_summary.get('advisory_action', 'unknown')}`,"
        f" `reason={startup_summary.get('advisory_reason', 'unknown')}`,"
        f" `startup_authority_ok={startup_summary.get('startup_authority_ok', False)}`,"
        f" `ahead_of_upstream_commits={startup_summary.get('ahead_of_upstream_commits', 'n/a')}` |",
        "| Review runtime | "
        f"`attention.status={review_summary.get('attention_status', 'unknown')}`,"
        f" `reviewer_freshness={review_summary.get('reviewer_freshness', 'unknown')}`,"
        f" `review_needed={review_summary.get('review_needed', 'n/a')}`,"
        f" `review_accepted={review_summary.get('review_accepted', 'n/a')}` |",
        "| Governance review | "
        f"`total_findings={governance_summary.get('total_findings', 'n/a')}`,"
        f" `open_finding_count={governance_summary.get('open_finding_count', 'n/a')}`,"
        f" `fixed_count={governance_summary.get('fixed_count', 'n/a')}`,"
        f" `cleanup_rate_pct={governance_summary.get('cleanup_rate_pct', 'n/a')}` |",
        "| Cross-repo imported findings | "
        f"`unique_repo_count={external_summary.get('unique_repo_count', 'n/a')}`,"
        f" `total_findings={external_summary.get('total_findings', 'n/a')}`,"
        f" `reviewed_count={external_summary.get('reviewed_count', 'n/a')}`,"
        f" `adjudication_coverage_pct={external_summary.get('adjudication_coverage_pct', 'n/a')}` |",
        "| Command/watchdog telemetry | "
        f"`total_events={data_science_summary.get('total_events', 'n/a')}`,"
        f" `command_success_rate_pct={data_science_summary.get('command_success_rate_pct', 'n/a')}`,"
        f" `watchdog_total_episodes={data_science_summary.get('watchdog_total_episodes', 'n/a')}`,"
        f" `watchdog_success_rate_pct={data_science_summary.get('watchdog_success_rate_pct', 'n/a')}` |",
        "",
        "This matters because the current repo state is being reduced from typed",
        "startup/review/evidence artifacts rather than hand-maintained prose.",
        "",
    ]


